select CONCAT(CONVERT(varchar(10),a.tran_date,23),' - ',a.seq) AS purDateSeq ,dbo.getCustomerName(a.customer_cd) as customer_name ,CASE WHEN COUNT(b.tran_item_id) = 1 THEN MIN(b.item_name) ELSE MIN(b.item_name) + ' 외 ' + CAST(COUNT(b.tran_item_id) - 1 AS VARCHAR) + '건' END AS item_name ,sum(isnull(b.qty, 0)) as totQty ,dbo.getStorageName(a.form_storage_cd) as form_storage_name ,dbo.getStorageName(a.to_storage_cd) as to_storage_name ,a.tran_status ,dbo.getUserName(a.manager_id) as manager_name ,a.tran_id from tb_inv_tran_mst a inner join tb_inv_tran_item b on a.pur_id = b.pur_id where a.tran_date between #{strDate} and #{toDate}
and b.item_cd = #{itemCd}
and b.item_name like '%' + #{itemName} + '%'
and dbo.getCustomerName(a.customer_cd) like '%' + #{customerName} + '%'
group by a.tran_id, a.tran_date, a.form_storage_cd, a.form_storage_cd, a.tran_status, a.customer_cd , a.manager_id order by a.pur_date desc, a.seq desc

