mapper.update:
UPDATE dbo.tb_inv_tran_mst
SET    tran_date        = #{tranDate}
      ,from_storage_cd  = #{fromStorageCd}
      ,to_storage_cd    = #{toStorageCd}
      ,customer_cd      = #{customerCd}
      ,manager_id       = #{managerId}
      ,remark           = #{remark}
      ,upd_id           = #{userId}
      ,upd_dt           = GETDATE()
WHERE  pur_id           = #{purId}
and    tran_type_cd = 'A'

UPDATE  tb_inv_tran_item
SET      spec         = #{spec}
        ,qty          = #{qty}
        ,lot_no       = #{lotNo}
        ,expiry_date  = #{expiryDate}
        ,etc          = #{etc}
        ,upd_id       = #{userId}
        ,upd_dt       = GETDATE()
WHERE pur_item_id  = #{purItemId}

